challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The AMF has exited, causing a complete failure in the 5G core network's control plane, preventing UEs from registering and establishing PDU sessions.",
      "primary_suspect_nf": "amf",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "for the 'amf' container",
          "expected_if_hypothesis_holds": "The container status is 'exited' or otherwise not 'running'.",
          "falsifying_observation": "The container status is 'running'.",
          "conflates_with": []
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from: nr_gnb, to: amf",
          "expected_if_hypothesis_holds": "100% packet loss; AMF is unreachable from the RAN.",
          "falsifying_observation": "0% packet loss and low latency; AMF is fully reachable from the RAN.",
          "conflates_with": [
            "A network partition on the N2 path between the gNB and the AMF could also cause this."
          ]
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from: nr_gnb, to: smf",
          "expected_if_hypothesis_holds": "0% packet loss; other core components are reachable, isolating the issue to AMF.",
          "falsifying_observation": "100% packet loss; if the SMF is also unreachable, it suggests a broader network issue, not an AMF-specific one.",
          "conflates_with": []
        }
      ],
      "notes": "This plan directly tests the primary claim of the hypothesis (container exit) and verifies the expected network-level impact on the N2 interface from the RAN. The failure of the AMF breaks the start of the 'ue_registration' and 'pdu_session_establishment' flows."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "The SMF is failing to establish or maintain PDU sessions, leading to a loss of user plane connectivity.",
      "primary_suspect_nf": "smf",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "for the 'smf' container",
          "expected_if_hypothesis_holds": "The container status is 'running' (as the failure is functional, not a crash).",
          "falsifying_observation": "The container status is 'exited', which would point to a different failure mode (and support h1 if the AMF is also down).",
          "conflates_with": []
        },
        {
          "tool": "get_flow",
          "args_hint": "flow_id: 'pdu_session_establishment'",
          "expected_if_hypothesis_holds": "The flow definition exists and involves the SMF interacting with the PCF (N7) and UPF (N4).",
          "falsifying_observation": "The flow is not defined or does not match the expected interactions, suggesting a misconfiguration.",
          "conflates_with": []
        },
        {
          "tool": "get_network_status",
          "args_hint": "for the 'pcf' container",
          "expected_if_hypothesis_holds": "The PCF container is 'running', as the hypothesis places the fault at the SMF.",
          "falsifying_observation": "The PCF container is 'exited', which would indicate that the SMF's failure to establish a session could be due to an unavailable PCF.",
          "conflates_with": []
        }
      ],
      "notes": "This plan investigates if the SMF is the bottleneck in the 'pdu_session_establishment' flow. It checks the SMF's own health and the health of its direct dependency (PCF) for session policy."
    },
    {
      "hypothesis_id": "h3",
      "hypothesis_statement": "The UPF is experiencing a data plane failure, preventing the forwarding of GTP-U traffic for active PDU sessions.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds: 60",
          "expected_if_hypothesis_holds": "Metrics for the UPF will show high packet loss, extremely low throughput, and poor MOS scores.",
          "falsifying_observation": "Metrics show low packet loss and healthy throughput/MOS, indicating the data plane is functional.",
          "conflates_with": [
            "Absence of GTP-U traffic from the RAN on the N3 interface; the UPF cannot forward traffic it never receives."
          ]
        },
        {
          "tool": "get_flow",
          "args_hint": "flow_id: 'vonr_call_setup'",
          "expected_if_hypothesis_holds": "The flow steps indicate that user plane traffic (RTP) passes through the UPF.",
          "falsifying_observation": "The flow does not route media through the UPF, which would be a fundamental architecture misunderstanding.",
          "conflates_with": []
        },
        {
          "tool": "check_process_listeners",
          "args_hint": "container: upf",
          "expected_if_hypothesis_holds": "The UPF process is listening on its N3 (GTP-U) and N4 (PFCP) ports.",
          "falsifying_observation": "The UPF process is not listening on one or both of its critical interface ports, indicating a crash or initialization failure.",
          "conflates_with": []
        }
      ],
      "notes": "This plan uses the activity-vs-drops discriminator pattern. Probe 1 checks for data plane activity at the UPF. Probe 2 (realized by the Investigator checking gNB metrics) will confirm if traffic is being sent *to* the UPF. This disambiguates a UPF failure from an upstream RAN issue."
    }
  ]
}

